1	//! Which side(s) of a workspace a command should operate on.
2	//!
3	//! - `Side` is the clap `ValueEnum` — one of `code`, `bot`.
4	//! - `Scope` wraps the parsed list; a missing flag (None at the arg
5	//!   layer) means "caller decides", typically via workspace-state
6	//!   default resolution.
7	//! - See `notes/chores-06.md > Generalize --scope across commands
8	//!   (0.40.0)` for the full rationale and the vocabulary history.
9	
10	use clap::ValueEnum;
11	
12	/// One side of the workspace.
13	///
14	/// - `Code` — the primary (app) repo.
15	/// - `Bot` — the Claude Code session repo (typically at `.claude/`).
16	#[derive(Copy, Clone, Debug, PartialEq, Eq, ValueEnum)]
17	pub enum Side {
18	    Code,
19	    Bot,
20	}
21	
22	/// Parsed `--scope` value: the set of sides the command applies to.
23	#[derive(Clone, Debug, PartialEq, Eq)]
24	pub struct Scope(pub Vec<Side>);
25	
26	impl Scope {
27	    /// True when the scope includes the code side.
28	    pub fn has_code(&self) -> bool {
29	        self.0.contains(&Side::Code)
30	    }
31	
32	    /// True when the scope includes the bot side.
33	    pub fn has_bot(&self) -> bool {
34	        self.0.contains(&Side::Bot)
35	    }
36	
37	    /// Exactly the code side — single-repo operation.
38	    pub fn is_code_only(&self) -> bool {
39	        self.has_code() && !self.has_bot()
40	    }
41	
42	    /// Exactly the bot side — single-repo operation on the bot.
43	    pub fn is_bot_only(&self) -> bool {
44	        !self.has_code() && self.has_bot()
45	    }
46	
47	    /// Both sides — dual-repo operation.
48	    pub fn is_both(&self) -> bool {
49	        self.has_code() && self.has_bot()
50	    }
51	
52	    /// Neither side — empty scope, always an invalid input.
53	    pub fn is_empty(&self) -> bool {
54	        self.0.is_empty()
55	    }
56	}
