1	use std::path::{Path, PathBuf};
2	use std::process::Command;
3	
4	use clap::Args;
5	use log::{LevelFilter, debug, info, warn};
6	
7	use crate::common::run;
8	
9	/// Fetch and sync a set of repos to their remotes.
10	///
11	/// Default is `--check`: fetch + classify + report, **error** if any
12	/// repo is `behind` or `diverged`. Pass `--no-check` to actually
13	/// rebase / fast-forward. On any failure the starting state of every
14	/// repo is restored via `jj op restore`.
15	///
16	/// Scripts and automation should pass `--check` or `--no-check`
17	/// explicitly rather than relying on the default — defaults can shift,
18	/// explicit flags lock in the contract.
19	///
20	/// Repo set defaults to the dual-repo workspace pair (`.` and
21	/// `.claude`); override with `-R` / `--repo` for single-repo projects
22	/// (e.g. `vc-template-x1`) or arbitrary multi-repo workspaces.
23	#[derive(Args, Debug)]
24	pub struct SyncArgs {
25	    /// Verify only — fetch + classify; error if any repo needs action.
26	    /// This is the default; pass explicitly in scripts.
27	    #[arg(long, conflicts_with = "no_check")]
28	    pub check: bool,
29	
30	    /// Apply — fetch + classify, then rebase / fast-forward as needed.
31	    #[arg(long, conflicts_with = "check")]
32	    pub no_check: bool,
33	
34	    /// Suppress all informational output (exit code signals result)
35	    #[arg(short, long)]
36	    pub quiet: bool,
37	
38	    /// Bookmark to sync in each repo
39	    #[arg(long, default_value = "main")]
40	    pub bookmark: String,
41	
42	    /// Remote to sync against
43	    #[arg(long, default_value = "origin")]
44	    pub remote: String,
45	
46	    /// Path to jj repo; repeatable or comma-separated [default: `.,.claude`]
47	    #[arg(short = 'R', long = "repo", value_name = "PATH")]
48	    pub repos: Vec<PathBuf>,
49	}
50	
51	/// Default repo set when `-R` isn't given — the canonical dual-repo pair.
52	const DEFAULT_REPOS: [&str; 2] = [".", ".claude"];
53	
54	/// Resolve the caller's `-R` flags into a concrete repo list.
55	///
56	/// Empty input (no `-R` given) falls back to `DEFAULT_REPOS`. Each
57	/// provided value is also split on `,` and trimmed, so
58	/// `-R .,.claude` works identically to `-R . -R .claude`.
59	fn resolve_repos(raw: &[PathBuf]) -> Vec<PathBuf> {
60	    if raw.is_empty() {
61	        return DEFAULT_REPOS.iter().map(PathBuf::from).collect();
62	    }
63	    raw.iter()
64	        .flat_map(|p| {
65	            p.to_string_lossy()
66	                .split(',')
67	                .map(|s| PathBuf::from(s.trim()))
68	                .collect::<Vec<_>>()
69	        })
70	        .collect()
71	}
72	
73	/// Relationship between a local bookmark and its remote counterpart.
74	#[derive(Debug, Clone, PartialEq, Eq)]
75	pub enum State {
76	    /// Local and remote point at the same commit.
77	    UpToDate,
78	    /// Local is a strict ancestor of remote — fast-forward possible.
79	    Behind { local: String, remote: String },
80	    /// Remote is a strict ancestor of local — nothing to pull in.
81	    Ahead { local: String, remote: String },
82	    /// Neither is an ancestor of the other — needs rebase.
83	    Diverged { local: String, remote: String },
84	    /// The bookmark has no `@<remote>` counterpart.
85	    NoRemote,
86	}
87	
88	/// Per-repo context accumulated between the snapshot and action phases.
89	#[derive(Debug)]
90	struct RepoCtx {
91	    path: PathBuf,
92	    #[allow(dead_code)]
93	    op_id: String,
94	    state: State,
95	}
96	
97	/// CLI entry point for the `sync` subcommand.
98	///
99	/// Thin wrapper over `sync_repos` that resolves the `-R` flag into a
100	/// concrete repo list (falling back to the dual-repo default) and
101	/// forwards the rest of the args. Tests call `sync_repos` directly
102	/// with absolute fixture paths.
103	///
104	/// When `--quiet` is set, the global log filter is temporarily clamped
105	/// to `Warn` for the duration of the call and restored on return, so
106	/// `info!` calls throughout sync (plus any subprocess-stderr routed
107	/// through `common::run`) go dark. Errors still surface at `Warn` /
108	/// `Error` so script callers don't lose diagnostics.
109	pub fn sync(args: &SyncArgs) -> Result<(), Box<dyn std::error::Error>> {
110	    let repos = resolve_repos(&args.repos);
111	    if args.quiet {
112	        let prev = log::max_level();
113	        log::set_max_level(LevelFilter::Warn);
114	        let result = sync_repos(&repos, args);
115	        log::set_max_level(prev);
116	        result
117	    } else {
118	        sync_repos(&repos, args)
119	    }
120	}
121	
122	/// Sync the given repos against their remotes.
123	///
124	/// Orchestrates the full flow: pre-flight clean-check on every repo,
125	/// snapshot each repo's current op id, then hand off to `run_plan` for
126	/// fetch + classify + (optional) act. On any error, revert every repo
127	/// to its snapshot op via `jj op restore` so the caller sees an atomic
128	/// "either it all went through or nothing changed" outcome.
129	///
130	/// Paths may be relative (resolved against the process cwd) or
131	/// absolute. Tests use absolute tempdir paths to avoid cwd dependence
132	/// under parallel `cargo test`.
133	pub fn sync_repos(repos: &[PathBuf], args: &SyncArgs) -> Result<(), Box<dyn std::error::Error>> {
134	    debug!(
135	        "sync: enter (no_check={}, bookmark={}, remote={})",
136	        args.no_check, args.bookmark, args.remote
137	    );
138	
139	    // Preflight: verify bookmark tracking on every repo before any
140	    // fetch/rebase. Implements "Non-tracking-remote bookmark detection"
141	    // — design at:
142	    //   https://github.com/winksaville/vc-x1/blob/main/notes/chores-06.md#non-tracking-remote-bookmark-detection-design
143	    for repo in repos {
144	        crate::common::verify_tracking(repo, &args.bookmark)?;
145	    }
146	
147	    let mut snapshots: Vec<(PathBuf, String)> = Vec::new();
148	    for repo in repos {
149	        let op_id = current_op_id(repo)?;
150	        debug!("{}: op snapshot = {op_id}", repo.display());
151	        snapshots.push((repo.clone(), op_id));
152	    }
153	
154	    let result = run_plan(&snapshots, args);
155	
156	    if let Err(e) = &result {
157	        warn!("sync failed: {e}");
158	        warn!("reverting all repos to starting state...");
159	        for (repo, op_id) in &snapshots {
160	            match op_restore(repo, op_id) {
161	                Ok(()) => info!("  {}: reverted to op {op_id}", repo.display()),
162	                Err(re) => warn!("  {}: revert failed: {re}", repo.display()),
163	            }
164	        }
165	    }
166	
167	    debug!("sync: exit");
168	    result
169	}
170	
171	/// Fetch and classify each repo, then act (or not, in dry-run).
172	///
173	/// Returns `Err` on the first failure so the caller can trigger the
174	/// cross-repo revert; partial success across repos is *not* a valid
175	/// end state for this command.
176	fn run_plan(
177	    snapshots: &[(PathBuf, String)],
178	    args: &SyncArgs,
179	) -> Result<(), Box<dyn std::error::Error>> {
180	    // Phase 1 — fetch + classify silently.
181	    //
182	    // Each repo's fetch stderr is captured (rather than streamed to
183	    // `info!` via `common::run`) so we can decide after classification
184	    // whether to surface it. `jj git fetch`'s routine "Nothing
185	    // changed." chatter is the main thing we're suppressing here —
186	    // if nothing needs action, the user shouldn't see it.
187	    let mut fetched: Vec<(PathBuf, String)> = Vec::new();
188	    let mut ctxs: Vec<RepoCtx> = Vec::new();
189	    for (repo, op_id) in snapshots {
190	        let stderr = fetch_silent(repo, &args.remote)?;
191	        fetched.push((repo.clone(), stderr));
192	        let state = classify(repo, &args.bookmark, &args.remote)?;
193	        ctxs.push(RepoCtx {
194	            path: repo.clone(),
195	            op_id: op_id.clone(),
196	            state,
197	        });
198	    }
199	
200	    let any_action_needed = ctxs
201	        .iter()
202	        .any(|c| matches!(c.state, State::Behind { .. } | State::Diverged { .. }));
203	
204	    // Phase 2 — emit status. `--quiet` is enforced globally via the
205	    // log-level clamp in `sync()`, so these `info!` calls are already
206	    // suppressed in scripts; we just shape the output here.
207	    if !any_action_needed {
208	        let n = ctxs.len();
209	        let noun = if n == 1 { "repo" } else { "repos" };
210	        info!("sync: {n} {noun}, all bookmarks up-to-date");
211	    } else {
212	        for (repo, stderr) in &fetched {
213	            info!("{}: fetch {}", repo.display(), args.remote);
214	            for line in stderr.lines() {
215	                info!("{line}");
216	            }
217	        }
218	        for ctx in &ctxs {
219	            log_state(&ctx.path, &ctx.state);
220	        }
221	    }
222	
223	    // Phase 3 — act (subprocess output streams through as usual).
224	    // `act_on_state` and `ensure_at_on_main` short-circuit when
225	    // `args.no_check` is false, so check mode is a true no-op here.
226	    for ctx in &ctxs {
227	        act_on_state(ctx, args)?;
228	        ensure_at_on_main(&ctx.path, &args.bookmark, args.no_check)?;
229	    }
230	
231	    // Phase 4 — check mode is fatal when action would be needed.
232	    // Apply mode (`--no-check`) ran the action above and is done.
233	    if !args.no_check && any_action_needed {
234	        let n_action = ctxs
235	            .iter()
236	            .filter(|c| matches!(c.state, State::Behind { .. } | State::Diverged { .. }))
237	            .count();
238	        let noun = if n_action == 1 { "repo" } else { "repos" };
239	        return Err(format!(
240	            "sync: {n_action} {noun} need action (see above) — \
241	             resolve with `vc-x1 sync --no-check` and re-run"
242	        )
243	        .into());
244	    }
245	    Ok(())
246	}
247	
248	/// Fetch `repo` from `remote` without streaming subprocess output to
249	/// `info!`.
250	///
251	/// Mirrors what `common::run` would do, but returns stderr to the
252	/// caller so the caller can decide whether to surface it (verbose /
253	/// action case) or drop it (clean case). Stdout is dropped — `jj git
254	/// fetch` doesn't use it. Failure carries stderr in the error message.
255	fn fetch_silent(repo: &Path, remote: &str) -> Result<String, Box<dyn std::error::Error>> {
256	    debug!("$ jj git fetch --remote {remote} -R {}", repo.display());
257	    let output = Command::new("jj")
258	        .args(["git", "fetch", "--remote", remote, "-R", &repo_str(repo)])
259	        .output()
260	        .map_err(|e| format!("failed to run jj git fetch: {e}"))?;
261	    let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
262	    let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
263	    if !stdout.is_empty() {
264	        debug!("  {stdout}");
265	    }
266	    if !output.status.success() {
267	        return Err(format!("jj git fetch -R {} failed: {stderr}", repo.display()).into());
268	    }
269	    Ok(stderr)
270	}
271	
272	/// Ensure `@` is a descendant of `bookmark`, rebasing if not.
273	///
274	/// `jj git fetch` fast-forwards a tracked local bookmark to the remote
275	/// tip when local is a strict ancestor, but leaves `@` behind — still
276	/// parented on the *pre-fetch* bookmark commit. The `.claude` repo is
277	/// the motivating case: trailing session writes (e.g. `/exit`'s jsonl
278	/// tail) sit in `@`, and without this step they'd end up orphaned on a
279	/// stale branch when the remote advanced.
280	///
281	/// Skipped when `main::@` is already non-empty (i.e., `@` is already
282	/// reachable from `bookmark`). On `--no-check`, runs
283	/// `jj rebase -b @ -d <bookmark>` which carries all commits between
284	/// the old parent and `@` forward, then checks `conflicts()` — any
285	/// conflict in this step trips the outer revert the same way a
286	/// conflicted `act_on_state` rebase would.
287	fn ensure_at_on_main(
288	    repo: &Path,
289	    bookmark: &str,
290	    apply: bool,
291	) -> Result<(), Box<dyn std::error::Error>> {
292	    if revset_nonempty(repo, &format!("{bookmark}::@"))? {
293	        return Ok(());
294	    }
295	    info!("{}: rebasing @ onto '{bookmark}'", repo.display());
296	    if apply {
297	        run(
298	            "jj",
299	            &["rebase", "-b", "@", "-d", bookmark, "-R", &repo_str(repo)],
300	            Path::new("."),
301	        )?;
302	        if has_conflicts(repo)? {
303	            return Err(format!(
304	                "{}: rebase of @ onto '{bookmark}' produced conflicts",
305	                repo.display()
306	            )
307	            .into());
308	        }
309	    }
310	    Ok(())
311	}
312	
313	/// Perform the mutation corresponding to `ctx.state` when `--no-check`.
314	///
315	/// - `UpToDate` / `Ahead` / `NoRemote` → no-op (and no output, the state
316	///   was already logged by `log_state`).
317	/// - `Behind` → `jj bookmark set <b> -r <b>@<remote>` to fast-forward.
318	/// - `Diverged` → `jj rebase -b <b> -d <b>@<remote>`, then probe
319	///   `conflicts()`. A non-empty result means the rebase produced
320	///   conflicted commits; return `Err` so the outer revert restores the
321	///   pre-fetch state.
322	fn act_on_state(ctx: &RepoCtx, args: &SyncArgs) -> Result<(), Box<dyn std::error::Error>> {
323	    let repo = &ctx.path;
324	    let remote_rev = format!("{}@{}", args.bookmark, args.remote);
325	    match &ctx.state {
326	        State::UpToDate | State::Ahead { .. } | State::NoRemote => Ok(()),
327	        State::Behind { .. } => {
328	            if args.no_check {
329	                info!("{}: fast-forwarding '{}'", repo.display(), args.bookmark);
330	                run(
331	                    "jj",
332	                    &[
333	                        "bookmark",
334	                        "set",
335	                        &args.bookmark,
336	                        "-r",
337	                        &remote_rev,
338	                        "-R",
339	                        &repo_str(repo),
340	                    ],
341	                    Path::new("."),
342	                )?;
343	            }
344	            Ok(())
345	        }
346	        State::Diverged { local, remote } => {
347	            if args.no_check {
348	                // `local` is either a single commit id or a comma-joined list
349	                // of heads when the bookmark is conflicted. Pick the head
350	                // that isn't the remote — that's the local-only tip. The
351	                // comma-joined path covers the jj post-fetch divergence
352	                // shape (local bookmark conflicted between old local head
353	                // and freshly-fetched remote head).
354	                let local_head = local
355	                    .split(',')
356	                    .find(|h| *h != remote)
357	                    .unwrap_or(local.as_str());
358	                info!(
359	                    "{}: rebasing {local_head} onto {remote_rev}",
360	                    repo.display()
361	                );
362	                run(
363	                    "jj",
364	                    &[
365	                        "rebase",
366	                        "-b",
367	                        local_head,
368	                        "-d",
369	                        &remote_rev,
370	                        "-R",
371	                        &repo_str(repo),
372	                    ],
373	                    Path::new("."),
374	                )?;
375	                if has_conflicts(repo)? {
376	                    return Err(format!("{}: rebase produced conflicts", repo.display()).into());
377	                }
378	            }
379	            Ok(())
380	        }
381	    }
382	}
383	
384	/// Print a single-line summary of `state` at `info!` level.
385	fn log_state(repo: &Path, state: &State) {
386	    let r = repo.display();
387	    match state {
388	        State::UpToDate => info!("{r}: up-to-date"),
389	        State::NoRemote => info!("{r}: no remote counterpart — skipping"),
390	        State::Ahead { local, remote } => {
391	            info!("{r}: ahead (local {local} > remote {remote}); nothing to sync")
392	        }
393	        State::Behind { local, remote } => {
394	            info!("{r}: behind (local {local} < remote {remote}); would fast-forward")
395	        }
396	        State::Diverged { local, remote } => {
397	            info!("{r}: diverged (local {local} vs remote {remote}); would rebase")
398	        }
399	    }
400	}
401	
402	/// Return the id of the most recent operation on `repo`.
403	///
404	/// Used as the revert target on failure. Exposed at `pub(crate)` so
405	/// `push` (0.37.0-2+) can reuse the same snapshot pattern for its
406	/// commit-stage rollback without duplicating the jj invocation.
407	pub(crate) fn current_op_id(repo: &Path) -> Result<String, Box<dyn std::error::Error>> {
408	    let out = run(
409	        "jj",
410	        &[
411	            "op",
412	            "log",
413	            "--no-graph",
414	            "-n",
415	            "1",
416	            "-T",
417	            "id.short(12)",
418	            "-R",
419	            &repo_str(repo),
420	        ],
421	        Path::new("."),
422	    )?;
423	    Ok(out.trim().to_string())
424	}
