440	/// Classify the relationship between `bookmark` and `bookmark@remote`.
441	///
442	/// Uses `bookmarks(<b>)` rather than the bare name so a conflicted
443	/// bookmark (jj's representation of a diverged fetch) resolves to all
444	/// of its heads instead of erroring. When the set has multiple heads,
445	/// the bookmark is conflicted and the repo is `Diverged` by definition.
446	/// Otherwise we compare the single local head against the single
447	/// remote commit via two revset-ancestry probes.
448	///
449	/// Returns `NoRemote` when `<b>@<remote>` does not resolve — the caller
450	/// logs a skip and moves on.
451	fn classify(
452	    repo: &Path,
453	    bookmark: &str,
454	    remote: &str,
455	) -> Result<State, Box<dyn std::error::Error>> {
456	    let local_heads = local_bookmark_heads(repo, bookmark)?;
457	    let remote_rev = format!("{bookmark}@{remote}");
458	    let Some(remote) = try_commit_id(repo, &remote_rev)? else {
459	        return Ok(State::NoRemote);
460	    };
461	    if local_heads.is_empty() {
462	        return Err(format!("{}: bookmark '{bookmark}' does not exist", repo.display()).into());
463	    }
464	    if local_heads.len() > 1 {
465	        // Conflicted bookmark — jj's shape for post-fetch divergence.
466	        let local = local_heads.join(",");
467	        return Ok(State::Diverged { local, remote });
468	    }
469	    let local = local_heads.into_iter().next().unwrap(); // OK: `len() > 1` arm handled above, `is_empty()` handled above
470	    if local == remote {
471	        return Ok(State::UpToDate);
472	    }
473	    let local_is_anc = revset_nonempty(repo, &format!("{local}::{remote_rev}"))?;
474	    let remote_is_anc = revset_nonempty(repo, &format!("{remote_rev}::{local}"))?;
475	    Ok(match (local_is_anc, remote_is_anc) {
476	        (true, _) => State::Behind { local, remote },
477	        (false, true) => State::Ahead { local, remote },
478	        (false, false) => State::Diverged { local, remote },
479	    })
480	}
481	
482	/// Return all commit ids the `bookmark` currently points at.
483	///
484	/// Normally a one-element vector; two or more elements indicate a
485	/// conflicted bookmark (jj's representation of diverged post-fetch
486	/// state, where the local bookmark has multiple heads).
487	fn local_bookmark_heads(
488	    repo: &Path,
489	    bookmark: &str,
490	) -> Result<Vec<String>, Box<dyn std::error::Error>> {
491	    let out = run(
492	        "jj",
493	        &[
494	            "log",
495	            "-r",
496	            &format!("bookmarks(exact:{bookmark})"),
497	            "--no-graph",
498	            "-T",
499	            r#"commit_id.short(12) ++ "\n""#,
500	            "-R",
501	            &repo_str(repo),
502	        ],
503	        Path::new("."),
504	    )?;
505	    Ok(out
506	        .lines()
507	        .map(|l| l.trim().to_string())
508	        .filter(|l| !l.is_empty())
509	        .collect())
510	}
511	
512	/// Return the short commit id that `rev` resolves to in `repo`.
513	///
514	/// Errors when the revset is unresolvable or matches multiple heads
515	/// — callers that want to tolerate "revset doesn't resolve" should use
516	/// `try_commit_id`.
517	fn commit_id(repo: &Path, rev: &str) -> Result<String, Box<dyn std::error::Error>> {
518	    let out = run(
519	        "jj",
520	        &[
521	            "log",
522	            "-r",
523	            rev,
524	            "--no-graph",
525	            "-T",
526	            "commit_id.short(12)",
527	            "-R",
528	            &repo_str(repo),
529	        ],
530	        Path::new("."),
531	    )?;
532	    Ok(out.trim().to_string())
533	}
534	
535	/// Like `commit_id`, but `Ok(None)` when the revset doesn't resolve.
536	///
537	/// jj reports missing revisions via stderr strings like
538	/// `Revision \`foo@origin\` doesn't exist` or `No such revision …`;
539	/// both get mapped to `Ok(None)` so callers can distinguish "missing"
540	/// from "other subprocess failure".
541	fn try_commit_id(repo: &Path, rev: &str) -> Result<Option<String>, Box<dyn std::error::Error>> {
542	    match commit_id(repo, rev) {
543	        Ok(id) if id.is_empty() => Ok(None),
544	        Ok(id) => Ok(Some(id)),
545	        Err(e) => {
546	            let msg = e.to_string();
547	            if msg.contains("doesn't exist") || msg.contains("No such revision") {
548	                Ok(None)
549	            } else {
550	                Err(e)
551	            }
552	        }
553	    }
554	}
555	
556	/// Return `true` when `revset` matches at least one commit in `repo`.
557	fn revset_nonempty(repo: &Path, revset: &str) -> Result<bool, Box<dyn std::error::Error>> {
558	    let out = run(
559	        "jj",
560	        &[
561	            "log",
562	            "-r",
563	            revset,
564	            "--no-graph",
565	            "-T",
566	            r#"commit_id.short() ++ "\n""#,
567	            "-R",
568	            &repo_str(repo),
569	        ],
570	        Path::new("."),
571	    )?;
572	    Ok(!out.trim().is_empty())
573	}
574	
575	/// Return `true` when `repo` has any conflicted commits.
576	fn has_conflicts(repo: &Path) -> Result<bool, Box<dyn std::error::Error>> {
577	    revset_nonempty(repo, "conflicts()")
578	}
