    pub check: bool,

    /// Apply — fetch + classify, then rebase / fast-forward as needed.
    #[arg(long, conflicts_with = "check")]
    pub no_check: bool,

    /// Suppress all informational output (exit code signals result)
    #[arg(short, long)]
    pub quiet: bool,

