        claude_had_changes: Some(false),
        op_app: None,
        op_claude: None,
        title: None,
        body: None,
    };
    original.save(&path).expect("save");
    let loaded = PushState::load(&path).expect("load").expect("Some state");
    assert_eq!(loaded.claude_had_changes, Some(false));
    let _ = fs::remove_dir_all(&tmp);
}

