113	/// Resolve positional and flag args into a `DotSpec` ready for `collect_ids`.
114	///
115	/// Handles: dot notation parsing, flag vs positional precedence,
116	/// count-means-total semantics (subtracts 1 for anchor).
117	pub fn resolve_spec(
118	    pos_rev: Option<&str>,
119	    pos_count: Option<usize>,
120	    flag_rev: &str,
121	    flag_limit: Option<usize>,
122	    default_rev: &str,
123	) -> DotSpec {
124	    let flag_rev_set = flag_rev != default_rev;
125	    let rev_str = if flag_rev_set {
126	        flag_rev
127	    } else {
128	        pos_rev.unwrap_or(default_rev) // OK: positional absent → fall back to CLI default
129	    };
130	    let mut spec = parse_dot_rev(rev_str);
131	
132	    let count = if flag_limit.is_some() {
133	        flag_limit
134	    } else {
135	        pos_count
136	    };
137	
138	    if let Some(c) = count {
139	        let n = c.saturating_sub(1);
140	        let both_open = spec.desc_count.is_none() && spec.anc_count.is_none();
141	        if both_open {
142	            // Split budget across both sides: ancestors get the extra
143	            let desc_n = n / 2;
144	            let anc_n = n - desc_n;
145	            spec.desc_count = Some(desc_n);
146	            spec.anc_count = Some(anc_n);
147	        } else {
148	            if spec.desc_count.is_none() {
149	                spec.desc_count = Some(n);
150	            }
151	            if spec.anc_count.is_none() {
152	                spec.anc_count = Some(n);
153	            }
154	            // bare `x 5` → treat as `x.. 5` (ancestors)
155	            if spec.desc_count == Some(0) && spec.anc_count == Some(0) {
156	                spec.anc_count = Some(n);
157	            }
158	        }
159	    }
160	
161	    spec
162	}
